import React, { useEffect, useState } from "react";
import { base_url } from "../utils/axiosConfig";
import { toast } from "react-toastify";
import { Link } from "react-router-dom";

const STYLES = `
  @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');

  @keyframes profFadeUp {
    from { opacity: 0; transform: translateY(20px); }
    to   { opacity: 1; transform: translateY(0); }
  }
  @keyframes avatarRing {
    0%,100% { box-shadow: 0 0 0 0 rgba(20,184,166,0.35); }
    50%      { box-shadow: 0 0 0 14px rgba(20,184,166,0); }
  }

  .prof-page {
    font-family: 'Inter', sans-serif;
    background: #f8fafc;
    min-height: 100vh;
    padding-top: 80px;
    padding-bottom: 100px;
  }
  @media (max-width: 768px) { .prof-page { padding-top: 60px; } }

  /* Breadcrumb */
  .prof-breadcrumb {
    max-width: 660px; margin: 0 auto;
    padding: 20px 20px 0;
    display: flex; align-items: center; gap: 8px;
    font-size: 12px; color: #94a3b8; font-weight: 500;
  }
  .prof-breadcrumb a { color: #94a3b8; text-decoration: none; }
  .prof-breadcrumb a:hover { color: #14b8a6; }
  .prof-breadcrumb span { color: #1e293b; font-weight: 700; }

  /* Card container */
  .prof-wrap {
    max-width: 660px; margin: 20px auto 0;
    padding: 0 16px;
    animation: profFadeUp 0.5s ease;
  }

  .prof-card {
    background: #fff;
    border-radius: 28px;
    border: 1px solid #e2e8f0;
    overflow: hidden;
    box-shadow: 0 4px 24px rgba(0,0,0,0.06);
  }

  /* Card header */
  .prof-header {
    background: linear-gradient(135deg, #14b8a6 0%, #0d9488 50%, #0a7c70 100%);
    padding: 44px 32px 70px;
    text-align: center;
    position: relative;
  }
  .prof-header::before {
    content: '';
    position: absolute; inset: 0;
    background: radial-gradient(ellipse 60% 50% at 50% 0%, rgba(255,255,255,0.1) 0%, transparent 70%);
    pointer-events: none;
  }
  .prof-header::after {
    content: '';
    position: absolute;
    bottom: -1px; left: 0; right: 0;
    height: 40px;
    background: #fff;
    border-radius: 28px 28px 0 0;
  }

  .prof-avatar {
    width: 88px; height: 88px;
    border-radius: 50%; margin: 0 auto 16px;
    background: rgba(255,255,255,0.2);
    border: 3px solid rgba(255,255,255,0.5);
    display: flex; align-items: center; justify-content: center;
    font-size: 32px; font-weight: 900; color: #fff;
    letter-spacing: -1px;
    animation: avatarRing 2.5s ease-in-out infinite;
    backdrop-filter: blur(8px);
    position: relative; z-index: 1;
  }
  .prof-name {
    font-size: 26px; font-weight: 900; color: #fff;
    letter-spacing: -0.04em; margin: 0 0 5px;
    position: relative; z-index: 1;
  }
  .prof-role {
    font-size: 11px; font-weight: 800; letter-spacing: 0.2em;
    text-transform: uppercase; color: rgba(255,255,255,0.65);
    margin: 0; position: relative; z-index: 1;
  }

  /* Stats row */
  .prof-stats {
    display: flex; gap: 0;
    border-bottom: 1px solid #f1f5f9;
    margin-top: -28px;
  }
  .prof-stat {
    flex: 1; text-align: center;
    padding: 20px 8px 16px;
    border-right: 1px solid #f1f5f9;
    position: relative; z-index: 1;
  }
  .prof-stat:last-child { border-right: none; }
  .prof-stat-val { font-size: 20px; font-weight: 900; color: #0d9488; line-height: 1; margin-bottom: 4px; display: block; }
  .prof-stat-label { font-size: 10px; font-weight: 700; letter-spacing: 0.12em; text-transform: uppercase; color: #94a3b8; }

  /* Detail list */
  .prof-detail-head {
    display: flex; align-items: center; gap: 8px;
    padding: 20px 24px 14px;
    font-size: 10px; font-weight: 900; letter-spacing: 0.22em;
    text-transform: uppercase; color: #94a3b8;
  }
  .prof-detail-head-line { flex: 1; height: 1px; background: #f1f5f9; }

  .prof-detail-row {
    display: flex; align-items: center;
    justify-content: space-between;
    padding: 14px 24px;
    border-bottom: 1px solid #f8fafc;
    transition: background 0.18s;
  }
  .prof-detail-row:last-child { border-bottom: none; }
  .prof-detail-row:hover { background: #fafafa; }

  .prof-detail-left { display: flex; align-items: center; gap: 12px; }
  .prof-detail-icon {
    width: 34px; height: 34px; border-radius: 10px;
    background: #f0fdfa; display: flex; align-items: center; justify-content: center;
    font-size: 15px; flex-shrink: 0;
  }
  .prof-detail-label {
    font-size: 11px; font-weight: 800; letter-spacing: 0.12em;
    text-transform: uppercase; color: #94a3b8;
  }
  .prof-detail-val {
    font-size: 14px; font-weight: 600; color: #1e293b;
    text-align: right; max-width: 220px;
    overflow: hidden; text-overflow: ellipsis; white-space: nowrap;
  }
  @media (max-width: 400px) { .prof-detail-val { max-width: 140px; font-size: 13px; } }

  /* Action buttons */
  .prof-actions {
    padding: 20px 24px 28px;
    display: flex; flex-direction: column; gap: 12px;
    border-top: 1px solid #f1f5f9;
  }
  .prof-btn {
    display: flex; align-items: center; justify-content: center; gap: 8px;
    width: 100%; padding: 14px;
    border-radius: 16px; border: none;
    font-size: 13px; font-weight: 800;
    font-family: 'Inter', sans-serif;
    letter-spacing: 0.1em; text-transform: uppercase;
    cursor: pointer; text-decoration: none;
    transition: all 0.22s;
  }
  .prof-btn--primary {
    background: linear-gradient(135deg, #14b8a6, #0d9488);
    color: #fff;
    box-shadow: 0 6px 20px rgba(20,184,166,0.3);
  }
  .prof-btn--primary:hover { transform: translateY(-2px); box-shadow: 0 10px 28px rgba(20,184,166,0.4); color: #fff; }

  .prof-btn--secondary {
    background: #f8fafc; color: #0d9488;
    border: 1.5px solid #ccfbf1;
  }
  .prof-btn--secondary:hover { background: #f0fdfa; border-color: #99f6e4; }

  .prof-btn--danger {
    background: #fef2f2; color: #dc2626;
    border: 1.5px solid #fecaca;
  }
  .prof-btn--danger:hover { background: #fee2e2; border-color: #fca5a5; }

  /* Confirm modal */
  .prof-modal-bg {
    position: fixed; inset: 0;
    background: rgba(0,0,0,0.45);
    backdrop-filter: blur(6px);
    z-index: 99999;
    display: flex; align-items: center; justify-content: center;
    padding: 20px;
    animation: profFadeUp 0.2s ease;
  }
  .prof-modal {
    background: #fff; max-width: 400px; width: 100%;
    padding: 36px 32px; border-radius: 28px;
    box-shadow: 0 32px 80px rgba(0,0,0,0.2);
    text-align: center;
    animation: profFadeUp 0.3s cubic-bezier(0.34,1.1,0.64,1);
  }
  .prof-modal-icon {
    width: 60px; height: 60px; border-radius: 50%;
    background: #fef2f2; margin: 0 auto 18px;
    display: flex; align-items: center; justify-content: center; font-size: 26px;
  }
  .prof-modal-title { font-size: 21px; font-weight: 900; color: #dc2626; margin: 0 0 10px; }
  .prof-modal-text { font-size: 14px; color: #64748b; line-height: 1.65; margin-bottom: 28px; }
  .prof-modal-btns { display: flex; gap: 12px; justify-content: center; }
  .prof-modal-cancel {
    padding: 12px 24px; background: #f3f4f6; color: #374151;
    border: none; border-radius: 12px;
    font-size: 13px; font-weight: 700; font-family: 'Inter', sans-serif;
    cursor: pointer; transition: background 0.2s;
  }
  .prof-modal-cancel:hover { background: #e5e7eb; }
  .prof-modal-confirm {
    padding: 12px 24px;
    background: linear-gradient(135deg, #dc2626, #b91c1c);
    color: #fff; border: none; border-radius: 12px;
    font-size: 13px; font-weight: 800; font-family: 'Inter', sans-serif;
    cursor: pointer; transition: all 0.2s;
    box-shadow: 0 4px 14px rgba(220,38,38,0.3);
  }
  .prof-modal-confirm:hover { transform: translateY(-1px); box-shadow: 0 8px 22px rgba(220,38,38,0.4); }
`;

export default function Profile() {
  const [user, setUser] = useState(null);
  const [showModal, setShowModal] = useState(false);

  useEffect(() => {
    const stored = localStorage.getItem("customer");
    if (stored) {
      try {
        setUser(JSON.parse(stored));
      } catch (e) {
        console.error(e);
      }
    }
  }, []);

  const confirmDelete = async () => {
    try {
      const res = await fetch(`${base_url}user/${user._id}`, {
        method: "DELETE",
        headers: { Authorization: `Bearer ${user.token}` },
      });
      if (res.ok) {
        localStorage.removeItem("customer");
        toast.success("Account deleted.");
        window.location.href = "/";
      } else {
        toast.error("Failed to delete account.");
      }
    } catch (e) {
      console.error(e);
    } finally {
      setShowModal(false);
    }
  };

  if (!user) {
    return (
      <>
        <style>{STYLES}</style>
        <div
          style={{
            minHeight: "100vh",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            flexDirection: "column",
            gap: 16,
            background: "#f8fafc",
            fontFamily: "Inter,sans-serif",
          }}
        >
          <div
            style={{
              width: 48,
              height: 48,
              border: "4px solid #e2e8f0",
              borderTopColor: "#14b8a6",
              borderRadius: "50%",
              animation: "profFadeUp 0.8s linear infinite",
            }}
          />
          <span style={{ color: "#94a3b8", fontSize: 14, fontWeight: 600 }}>
            Loading profile…
          </span>
        </div>
      </>
    );
  }

  const initials =
    `${user.firstname?.charAt(0) || ""}${user.lastname?.charAt(0) || ""}`.toUpperCase() ||
    "?";
  const fullName = `${user.firstname || ""} ${user.lastname || ""}`.trim();

  const details = [
    { icon: "👤", label: "First Name", value: user.firstname },
    { icon: "👤", label: "Last Name", value: user.lastname },
    { icon: "✉️", label: "Email", value: user.email },
    { icon: "📱", label: "Mobile", value: user.mobile },
    { icon: "🔐", label: "Account Type", value: user.role || "Member" },
  ];

  return (
    <>
      <style>{STYLES}</style>

      <main className="main__content_wrapper prof-page">
        {/* Breadcrumb */}
        <nav className="prof-breadcrumb" aria-label="Breadcrumb">
          <Link to="/">Home</Link>
          <span>›</span>
          <span>Profile</span>
        </nav>

        <div className="prof-wrap">
          <div className="prof-card">
            {/* Header */}
            <div className="prof-header">
              <div className="prof-avatar">{initials}</div>
              <h1 className="prof-name">{fullName || "My Account"}</h1>
              <p className="prof-role">{user.role || "Member"}</p>
            </div>

            {/* Stats */}
            <div className="prof-stats">
              {[
                { val: "✓", label: "Verified" },
                {
                  val: user.role === "admin" ? "Admin" : "User",
                  label: "Role",
                },
                { val: "Active", label: "Status" },
              ].map(({ val, label }) => (
                <div key={label} className="prof-stat">
                  <span className="prof-stat-val">{val}</span>
                  <span className="prof-stat-label">{label}</span>
                </div>
              ))}
            </div>

            {/* Detail section header */}
            <div className="prof-detail-head">
              <span>Account Information</span>
              <div className="prof-detail-head-line" />
            </div>

            {/* Detail rows */}
            {details.map(({ icon, label, value }) => (
              <div key={label} className="prof-detail-row">
                <div className="prof-detail-left">
                  <div className="prof-detail-icon">{icon}</div>
                  <span className="prof-detail-label">{label}</span>
                </div>
                <span className="prof-detail-val">{value || "—"}</span>
              </div>
            ))}

            {/* Actions */}
            <div className="prof-actions">
              <Link to="/myaccount" className={`prof-btn prof-btn--primary`}>
                <svg
                  width="15"
                  height="15"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="2.5"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                >
                  <path d="M6 2 3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z" />
                  <line x1="3" y1="6" x2="21" y2="6" />
                  <path d="M16 10a4 4 0 0 1-8 0" />
                </svg>
                View My Orders
              </Link>
              <Link to="/wishlist" className={`prof-btn prof-btn--secondary`}>
                <svg
                  width="15"
                  height="15"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="2.5"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                >
                  <path d="M19 14c1.49-1.46 3-3.21 3-5.5A5.5 5.5 0 0 0 16.5 3c-1.76 0-3 .5-4.5 2-1.5-1.5-2.74-2-4.5-2A5.5 5.5 0 0 0 2 8.5c0 2.3 1.5 4.05 3 5.5l7 7Z" />
                </svg>
                My Wishlist
              </Link>
              <button
                className="prof-btn prof-btn--danger"
                onClick={() => setShowModal(true)}
              >
                <svg
                  width="15"
                  height="15"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="2.5"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                >
                  <polyline points="3 6 5 6 21 6" />
                  <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6" />
                  <path d="M10 11v6" />
                  <path d="M14 11v6" />
                </svg>
                Delete My Account
              </button>
            </div>
          </div>
        </div>
      </main>

      {/* Confirm delete modal */}
      {showModal && (
        <div className="prof-modal-bg" onClick={() => setShowModal(false)}>
          <div className="prof-modal" onClick={(e) => e.stopPropagation()}>
            <div className="prof-modal-icon">⚠️</div>
            <h2 className="prof-modal-title">Delete Account?</h2>
            <p className="prof-modal-text">
              This is permanent and cannot be undone.
              <br />
              All your data will be removed.
            </p>
            <div className="prof-modal-btns">
              <button
                className="prof-modal-cancel"
                onClick={() => setShowModal(false)}
              >
                Cancel
              </button>
              <button className="prof-modal-confirm" onClick={confirmDelete}>
                Yes, Delete
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}
